1891:      * retention or because the log size is > retentionSize. Whether or not deletion is enabled, delete any local
1892:      * log segments that are before the log start offset
1893:      */
1894:     public int deleteOldSegments() throws IOException {
1895:         if (config().delete) {
1896:             return deleteLogStartOffsetBreachedSegments() +
1897:                     deleteRetentionSizeBreachedSegments() +
1898:                     deleteRetentionMsBreachedSegments();
1899:         } else {
1900:             return deleteLogStartOffsetBreachedSegments();
1901:         }
1902:     }
1903: 
1904:     public interface DeletionCondition {
1905:         boolean execute(LogSegment segment, Optional<LogSegment> nextSegmentOpt) throws IOException;
1906:     }
1907: 
1908:     private int deleteRetentionMsBreachedSegments() throws IOException {
1909:         long retentionMs = UnifiedLog.localRetentionMs(config(), remoteLogEnabledAndRemoteCopyEnabled());
1910:         if (retentionMs < 0) return 0;
1911:         long startMs = time().milliseconds();
1912: 
1913:         DeletionCondition shouldDelete = (segment, nextSegmentOpt) -> {
1914:             if (startMs < segment.largestTimestamp()) {
1915:                 futureTimestampLogger.warn("{} contains future timestamp(s), making it ineligible to be deleted", segment);
1916:             }
1917:             boolean delete = startMs - segment.largestTimestamp() > retentionMs;
1918:             logger.debug("{} retentionMs breached: {}, startMs={}, retentionMs={}",
1919:                     segment, delete, startMs, retentionMs);
1920:             return delete;
1921:         };
1922:         return deleteOldSegments(shouldDelete, toDelete -> {
1923:             long localRetentionMs = UnifiedLog.localRetentionMs(config(), remoteLogEnabledAndRemoteCopyEnabled());
1924:             for (LogSegment segment : toDelete) {
1925:                 if (segment.largestRecordTimestamp().isPresent()) {
1926:                     if (remoteLogEnabledAndRemoteCopyEnabled()) {
1927:                         logger.info("Deleting segment {} due to local log retention time {}ms breach based on the largest " +
1928:                                 "record timestamp in the segment", segment, localRetentionMs);
1929:                     } else {
1930:                         logger.info("Deleting segment {} due to log retention time {}ms breach based on the largest " +
1931:                                 "record timestamp in the segment", segment, localRetentionMs);
1932:                     }
1933:                 } else {
1934:                     if (remoteLogEnabledAndRemoteCopyEnabled()) {
1935:                         logger.info("Deleting segment {} due to local log retention time {}ms breach based on the " +
1936:                                 "last modified time of the segment", segment, localRetentionMs);
1937:                     } else {
1938:                         logger.info("Deleting segment {} due to log retention time {}ms breach based on the " +
1939:                                 "last modified time of the segment", segment, localRetentionMs);
1940:                     }
1941:                 }
1942:             }
1943:         });
1944:     }
1945: 
1946:     private int deleteRetentionSizeBreachedSegments() throws IOException {
1947:         long retentionSize = UnifiedLog.localRetentionSize(config(), remoteLogEnabledAndRemoteCopyEnabled());
1948:         long logSize = size();
1949:         if (retentionSize < 0 || logSize < retentionSize) return 0;
1950:         final AtomicLong diff = new AtomicLong(logSize - retentionSize);
1951: 
1952:         DeletionCondition shouldDelete = (segment, nextSegmentOpt) -> {
1953:             int segmentSize = segment.size();
1954:             boolean delete = diff.get() - segmentSize >= 0;
1955:             logger.debug("{} retentionSize breached: {}, log size before delete segment={}, after delete segment={}",
1956:                     segment, delete, diff.get(), diff.get() - segmentSize);
1957:             if (delete) {
1958:                 diff.addAndGet(-segmentSize);
1959:             }
1960:             return delete;
